func SetupRouter(h *handler.UserHandler) *gin.Engine { r := gin.New() // not gin.Default()
// Middleware order: Recovery → Logger → RequestID r.Use(middleware.Recovery()) r.Use(middleware.Logger()) r.Use(middleware.RequestID())
r.GET("/healthz", func(c *gin.Context) { c.JSON(200, gin.H{"status": "ok"}) }) r.GET("/readyz", func(c *gin.Context) { c.JSON(200, gin.H{"status": "ok"}) })
v1 := r.Group("/api/v1") users := v1.Group("/users") users.Use(middleware.Auth()) { users.GET("", h.ListUsers) users.GET("/:id", h.GetUser) users.POST("", h.CreateUser) users.PUT("/:id", h.UpdateUser) users.DELETE("/:id", h.DeleteUser) }
return r }

type CreateUserRequest struct {
    Name  string `json:"name"  binding:"required,min=2,max=100"`
    Email string `json:"email" binding:"required,email"`
    Age   int    `json:"age"   binding:"gte=0,lte=130"`
}

func (h *UserHandler) CreateUser(c *gin.Context) {
    var req CreateUserRequest
    if err := c.ShouldBindJSON(&req); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }
    user, err := h.svc.CreateUser(c.Request.Context(), req)
    if err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": "internal error"})
        return
    }
    c.JSON(http.StatusCreated, gin.H{"data": user})
}
